import{_ as i,o as a,c as e,a2 as l}from"./chunks/framework.DIMps2S2.js";const c=JSON.parse('{"title":"网银转账入金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"deposit/hk-methods/online-banking-transfer.md","filePath":"zh-CN/deposit/hk-methods/online-banking-transfer.md"}'),r={name:"deposit/hk-methods/online-banking-transfer.md"};function o(n,t,d,s,h,p){return a(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="网银转账入金" tabindex="-1">网银转账入金 <a class="header-anchor" href="#网银转账入金" aria-label="Permalink to &quot;网银转账入金&quot;">​</a></h1><p>通过手机银行或网上银行将资金转账至长桥收款银行账户，转账完成后需上传汇款凭证。</p><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>支持币种</td><td>港元（HKD）、美元（USD）</td></tr><tr><td>预计到账时间</td><td>同行转账约 2 小时；跨行转账 1–3 个工作日</td></tr><tr><td>手续费</td><td>长桥免费；港币同行/跨行银行不收费；美元同行银行不收费；美元跨行：工银亚洲收 1.3 USD，中银香港/汇丰收 15 HKD</td></tr></tbody></table><h2 id="收款银行信息" tabindex="-1">收款银行信息 <a class="header-anchor" href="#收款银行信息" aria-label="Permalink to &quot;收款银行信息&quot;">​</a></h2><p><strong>港币收款账户（工商银行亚洲 072）</strong></p><ul><li>收款人名称：Long Bridge HK Limited</li><li>港元收款账号：861520160012</li><li>SWIFT 代码：UBHKHKHHXXX</li><li>汇款备注：证券账户名（账号 + 姓名），<strong>必填</strong></li></ul><p><strong>美元收款账户（创兴银行 041）</strong></p><ul><li>收款人名称：Long Bridge HK Limited</li><li>美元收款账号：256150608546</li><li>SWIFT 代码：LCHBHKHH</li><li>汇款备注：证券账户名（账号 + 姓名），<strong>必填</strong></li></ul><p>费用承担方：SHA（共同）</p><p><strong>海外银行电汇入金（仅 USD）</strong></p><p>适用于美国、马来西亚、新加坡、澳大利亚等境外银行：</p><ul><li>收款账号：861530198867</li><li>收款银行：072 中国工商银行（亚洲），SWIFT：UBHKHKHHXXX</li><li>预计到账时间：2–5 个交易日</li><li>仅支持 FATF 成员国家/地区，<strong>不支持中国大陆内地银行卡</strong></li></ul><h2 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h2><ol><li>打开长桥 App，进入<strong>资产 → 存入资金 → 选择入金币种 → 选择香港银行卡 → 网银转账</strong>，查看收款银行信息</li><li>在银行手机端或网页端完成转账，截图保留汇款凭证</li><li>返回长桥 App，上传汇款凭证截图</li></ol><blockquote><p>请在汇款完成后立即上传凭证。若有多笔入账，请每笔分别上传凭证。</p></blockquote><p>长桥 App 入金页面提供汇丰银行、恒生银行、中银香港、香港渣打银行、招行香港、民生银行、工银亚洲、众安银行、花旗银行等详细操作步骤。</p><h2 id="账户要求与工银多币种说明" tabindex="-1">账户要求与工银多币种说明 <a class="header-anchor" href="#账户要求与工银多币种说明" aria-label="Permalink to &quot;账户要求与工银多币种说明&quot;">​</a></h2><ul><li>转账银行账户名必须与证券账户名同名，不可使用他人或联名账户</li><li>不支持信用卡入金，即使收到资金也会原路退款</li><li>工银亚洲多币种账户：港币分币种账号尾号为 1 或 2，美元分币种账号尾号为 3 或 5，请汇款前确认</li><li>中银香港自 2025 年 11 月 1 日起，持卡客户无论是否完成见证，均支持中银同行入金</li><li>香港节假日不处理汇款业务，请预留时间</li></ul><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/deposit/methods-overview">入金方式总览</a> — 对比所有入金方式的预计到账时间与手续费</li><li><a href="/wiki/troubleshooting/deposit-not-received">入金未到账排查</a> — 超出预期时间未到账时的排查步骤</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/deposit">入金</a></li></ul>',23)])])}const b=i(r,[["render",o]]);export{c as __pageData,b as default};
